SELECT
ID,
PAYMENT_METHOD_CODE,
PAYMENT_METHOD_NAME,
PAYMENT_TYPE_CODE,
PAYMENT_TYPE_NAME,
BANK_CODE,
BANK_ID,
BANK_NAME,
COMPANY_NAME,
COMPANY_ID,
IS_DEFAULT,
CREATE_BY,
CREATE_BY_NAME,
CREATE_TIME,
UPDATE_BY,
UPDATE_BY_NAME,
UPDATE_TIME
FROM
T_FD_BANK_AFFILIATED


        and ID = #{id}


        and PAYMENT_METHOD_CODE = #{paymentMethodCode}


        and BANK_ID = #{bankId}


        and PAYMENT_METHOD_NAME = #{paymentMethodName}


        and PAYMENT_TYPE_CODE = #{paymentTypeCode}


        and PAYMENT_TYPE_NAME = #{paymentTypeName}


        and BANK_CODE = #{bankCode}


        and BANK_NAME = #{bankName}


        and COMPANY_NAME = #{companyName}


        and COMPANY_ID = #{companyId}


        and IS_DEFAULT = #{isDefault}
